1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.10;
3	
4	const BLOCK_OF_THREE_PRICE = 60;
5	
6	const BASE_PRICE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	function itemPremium(items: { type: string }[]): number {
16	  const countsByType: Record<string, number> = {};
17	  for (const item of items) {
18	    countsByType[item.type] = (countsByType[item.type] || 0) + 1;
19	  }
20	
21	  let totalBase = 0;
22	  for (const type in countsByType) {
23	    const count = countsByType[type];
24	    const isBlockOfThree = count === 3;
25	    if (isBlockOfThree) {
26	      totalBase += BLOCK_OF_THREE_PRICE;
27	    } else {
28	      totalBase += count * BASE_PRICE[type];
29	    }
30	  }
31	
32	  return totalBase + totalBase * FIRST_INSURANCE_RATE;
33	}
